        const urlSearchParams = new URLSearchParams(window.location.search);
        const params = Object.fromEntries(urlSearchParams.entries());
        let redirectUrl = window.location.href;
        let countdown = 4;
        let timeLeft = countdown;
        let monetization = false;
        let shortenedUrl = "null";

        function isValidHttpUrl(string) {
            let url;

            try {
                url = new URL(string);
            } catch (_) {
                return false;
            }

            return url.protocol === "http:" || url.protocol === "https:";
        }

        function redirect() {
            if (!params.start) {
                if (monetization && isValidHttpUrl(shortenedUrl)) {
                    window.location.href = shortenedUrl;
                } else {
                    window.location.href = redirectUrl + "&start=1";
                }
            }
        }

        var downloadTimer = setInterval(function () {
            if (timeLeft <= 0) {
                clearInterval(downloadTimer);
                redirect();
                document.getElementById("text").innerHTML = "Download has started.";
                document.getElementById("loader").src = "https://vidomon.com/wp-content/themes/aiodl-default/assets/icons/check-mark.svg";
            } else {
                document.getElementById("countdown").innerHTML = timeLeft + "";
            }
            timeLeft -= 1;
        }, 1000);
    </script>
